{
  "template": {
    "format_id": "amvision.workflow-graph-template.v1",
    "template_id": "industrial-local-directory-watch-detection-position-gate-template",
    "template_version": "1.0.0",
    "display_name": "Industrial Local Directory Watch Detection Position Gate",
    "description": "面向工业现场本地目录事件触发的检测到规则闭环样例。输入 directory-watch TriggerSource 标准化后的 payload 与 event、已发布 deployment 请求，以及可选运行时 ROI；按触发批次逐图执行检测，桥接为 regions.v1 后完成存在性、落位和偏移判定，并把单图结果持续追加到 CSV，再把整个批次收成统一 batch-record、JSON 归档和 HTTP 回传。",
    "nodes": [
      {
        "node_id": "wrap_trigger_payload",
        "node_type_id": "core.logic.payload-to-value",
        "parameters": {}
      },
      {
        "node_id": "wrap_trigger_event",
        "node_type_id": "core.logic.payload-to-value",
        "parameters": {}
      },
      {
        "node_id": "deployment_request_input",
        "node_type_id": "core.io.template-input.object",
        "parameters": {}
      },
      {
        "node_id": "extract_batch_files",
        "node_type_id": "core.logic.value-field-extract",
        "parameters": {
          "path": "files"
        }
      },
      {
        "node_id": "extract_batch_id",
        "node_type_id": "core.logic.value-field-extract",
        "parameters": {
          "path": "batch_id"
        }
      },
      {
        "node_id": "extract_scan_summary",
        "node_type_id": "core.logic.value-field-extract",
        "parameters": {
          "path": "scan_summary"
        }
      },
      {
        "node_id": "extract_directory_path",
        "node_type_id": "core.logic.value-field-extract",
        "parameters": {
          "path": "directory_path"
        }
      },
      {
        "node_id": "create_roi",
        "node_type_id": "core.vision.roi-create",
        "parameters": {
          "roi_kind": "bbox",
          "roi_id": "watch-position-roi",
          "display_name": "Directory Watch Position ROI",
          "bbox_xyxy": [
            220,
            140,
            1040,
            640
          ]
        }
      },
      {
        "node_id": "iterate_batch",
        "node_type_id": "core.logic.for-each",
        "parameters": {
          "body_node_ids": [
            "get_current_file_record",
            "get_current_file_index",
            "extract_current_file_path",
            "load_image",
            "detect",
            "detections_to_regions",
            "filter_regions",
            "select_best_region",
            "inside_check",
            "offset_check",
            "presence_check",
            "item_metadata_object",
            "item_metrics_object",
            "process_decision",
            "append_result_csv"
          ],
          "result_node_id": "process_decision",
          "result_port": "result",
          "item_variable_name": "file_record",
          "index_variable_name": "file_index"
        }
      },
      {
        "node_id": "get_current_file_record",
        "node_type_id": "core.logic.variable.get",
        "parameters": {
          "name": "file_record"
        }
      },
      {
        "node_id": "get_current_file_index",
        "node_type_id": "core.logic.variable.get",
        "parameters": {
          "name": "file_index"
        }
      },
      {
        "node_id": "extract_current_file_path",
        "node_type_id": "core.logic.value-field-extract",
        "parameters": {
          "path": "path"
        }
      },
      {
        "node_id": "load_image",
        "node_type_id": "core.io.image-load-local",
        "parameters": {}
      },
      {
        "node_id": "detect",
        "node_type_id": "core.model.yolox-detection",
        "parameters": {
          "auto_start_process": true,
          "score_threshold": 0.4,
          "save_result_image": false,
          "return_preview_image_base64": false
        }
      },
      {
        "node_id": "detections_to_regions",
        "node_type_id": "core.vision.detections-to-regions",
        "parameters": {
          "region_id_prefix": "det",
          "class_id_default": -1
        }
      },
      {
        "node_id": "filter_regions",
        "node_type_id": "core.vision.regions-filter",
        "parameters": {
          "class_names": [
            "part"
          ],
          "min_score": 0.55
        }
      },
      {
        "node_id": "select_best_region",
        "node_type_id": "core.vision.regions-select-best",
        "parameters": {
          "strategy": "largest-area"
        }
      },
      {
        "node_id": "inside_check",
        "node_type_id": "core.vision.regions-inside-check",
        "parameters": {
          "match_mode": "all",
          "min_inside_ratio": 0.95
        }
      },
      {
        "node_id": "offset_check",
        "node_type_id": "core.vision.regions-offset-check",
        "parameters": {
          "strategy": "largest-area",
          "max_distance_pixels": 28.0
        }
      },
      {
        "node_id": "presence_check",
        "node_type_id": "core.rule.presence-check",
        "parameters": {
          "min_count": 1,
          "max_count": 1
        }
      },
      {
        "node_id": "item_metadata_object",
        "node_type_id": "core.logic.object-create",
        "parameters": {
          "keys": [
            "file_record",
            "file_index",
            "deployment_request",
            "trigger_event",
            "batch_id"
          ],
          "fields": {
            "inspection_kind": "detection-position-gate-directory-watch",
            "station_id": "line-c-01",
            "trigger_kind": "directory-watch"
          }
        }
      },
      {
        "node_id": "item_metrics_object",
        "node_type_id": "core.logic.object-create",
        "parameters": {
          "keys": [
            "convert_summary",
            "filter_summary",
            "inside_metrics",
            "offset_metrics",
            "presence_metrics"
          ]
        }
      },
      {
        "node_id": "process_decision",
        "node_type_id": "core.rule.process-decision",
        "parameters": {
          "mode": "all",
          "condition_names": [
            "presence",
            "inside",
            "offset"
          ],
          "ok_reason": "directory watch detection position gate passed",
          "ng_reason": "directory watch detection position gate failed"
        }
      },
      {
        "node_id": "append_result_csv",
        "node_type_id": "core.output.csv-append-local",
        "parameters": {
          "local_path": "{workflow_app_result_dir}/industrial-local-directory-watch-detection-position-gate/history.csv"
        }
      },
      {
        "node_id": "batch_metadata_object",
        "node_type_id": "core.logic.object-create",
        "parameters": {
          "keys": [
            "trigger_event",
            "deployment_request",
            "batch_id",
            "directory_path"
          ],
          "fields": {
            "example_kind": "industrial-local-directory-watch-detection-position-gate",
            "trigger_source_kind": "directory-watch",
            "inspection_kind": "detection-position-gate-directory-watch",
            "station_id": "line-c-01",
            "callback_url": "http://127.0.0.1:18080/directory-watch/detection-position-batch-result"
          }
        }
      },
      {
        "node_id": "batch_record",
        "node_type_id": "core.output.batch-record",
        "parameters": {
          "record_kind": "directory-watch-batch-record",
          "include_result_summary": true
        }
      },
      {
        "node_id": "batch_result_summary",
        "node_type_id": "core.output.batch-result-summary",
        "parameters": {}
      },
      {
        "node_id": "save_batch_json",
        "node_type_id": "core.output.json-save-local",
        "parameters": {
          "local_path": "{workflow_app_result_dir}/industrial-local-directory-watch-detection-position-gate/result-{timestamp}.json",
          "overwrite": true,
          "indent": 2
        }
      },
      {
        "node_id": "callback_result",
        "node_type_id": "core.output.http-post",
        "parameters": {
          "url": "http://127.0.0.1:18080/directory-watch/detection-position-batch-result",
          "method": "POST",
          "timeout_seconds": 3.0,
          "require_success": false,
          "headers": {
            "X-Amvision-Example": "industrial-local-directory-watch-detection-position-gate"
          }
        }
      }
    ],
    "edges": [
      {
        "edge_id": "edge-wrap-trigger-payload-extract-files",
        "source_node_id": "wrap_trigger_payload",
        "source_port": "value",
        "target_node_id": "extract_batch_files",
        "target_port": "value"
